CollectorExporter.title:
message CloudProvider {
message Spec {
message Cloudflare {
// Email is the Cloudflare's account email
string email = 1;
// APIToken is the Cloudflare's API token.
message APIToken {
oneof type { string fromSecret = 1; }
}
APIToken apiToken = 2;
// Proxied sets the IP addresses to proxied mode. Not used currently.
bool proxied = 3;
}

message AWS {

// AccessKeyID is the `AWS_ACCESS_KEY_ID` value of your credentials.
string accessKeyID = 1;
// SecretAccessKey is the `AWS_SECRET_ACCESS_KEY` value for your
// credentials.

message SecretAccessKey {
oneof type { string fromSecret = 1; }
}

SecretAccessKey secretAccessKey = 2;

// Region is the AWS region code (e.g. `us-east-1`).
string region = 3;
// AssumeRoleARN is the assumed role (e.g.
// `arn:aws:iam::YYYYYYYYYYYY:role/dns-manager`)
string assumeRoleARN = 4;
}

message DigitalOcean {
message APIToken {
oneof type { string fromSecret = 1; }
}
APIToken apiToken = 1;
}

message Google {
// Project is the GCP project name.
string project = 1;

message ServiceAccount {
oneof type { string fromSecret = 1; }
}

ServiceAccount serviceAccount = 2;
}

message Azure {
message ClientSecret {
oneof type { string fromSecret = 1; }
}

string clientID = 1;
ClientSecret clientSecret = 2;
string subscriptionID = 3;
string tenantID = 4;
string resourceGroupName = 5;
// Cloud is the Azure cloud environment, valid values are `public`,
// `china`, `usgovernment` and `german`. Empty value is equivalent to
// `public`.
string cloud = 6;
}

message Linode {
message APIToken {
oneof type { string fromSecret = 1; }
}
APIToken apiToken = 1;
}

message OVH {
message ApplicationSecret {
oneof type { string fromSecret = 1; }
}
// Endpoint is the API endpoint (e.g. `ovh-eu`)
string endpoint = 1;
string applicationKey = 2;
ApplicationSecret applicationSecret = 3;
string consumerKey = 4;
}

message Alibaba {
message AccessKeySecret {
oneof type { string fromSecret = 1; }
}
string accessKeyID = 1;
AccessKeySecret accessKeySecret = 2;
string regionID = 3;
}

message Hetzner {
message APIToken {
oneof type { string fromSecret = 1; }
}
APIToken apiToken = 1;
}

message SMTP {
message Password {
oneof type { string fromSecret = 1; }
}

string host = 1;
int32 port = 2;
string username = 3;

Password password = 4;

string from = 5;
}

message Postgresql {

message Password {
oneof type { string fromSecret = 1; }
}

string username = 1;
Password password = 2;
string host = 3;
int32 port = 4;
string database = 5;
bool noSSL = 6;
}

message Redis {
message Password {
oneof type { string fromSecret = 1; }
}

string username = 1;
Password password = 2;
string host = 3;
int32 port = 4;
int32 database = 5;
bool useTLS = 6;
}

message S3 {
message SecretAccessKey {
oneof type { string fromSecret = 1; }
}

string endpoint = 1;
string accessKeyID = 2;
SecretAccessKey secretAccessKey = 3;
bool noTLS = 4;
string bucket = 5;
string region = 6;
}

message ContainerRegistry {
message Password {
oneof type { string fromSecret = 1; }
}

string server = 1;
string username = 2;
Password password = 3;
string namespace = 4;
}

oneof type {
Postgresql postgresql = 1;
// Cloudflare is Cloudflare's specific options.
Cloudflare cloudflare = 2;
// AWS is AWS's Route53 specific options.
AWS aws = 3;
// Digitalocean is DigitalOcean's specific options.
DigitalOcean digitalocean = 4;
// Google is GCP's Cloud DNS specific options.
Google google = 5;
// Azure is Azure DNS specific options.
Azure azure = 6;
// Linode is Linode's specific options.
Linode linode = 7;
// OVH is OVH specific options.
OVH ovh = 8;
// Alibaba is Alibaba's specific options.
Alibaba alibaba = 9;

Hetzner hetzner = 10;
SMTP smtp = 11;

Redis redis = 12;
S3 s3 = 13;

ContainerRegistry containerRegistry = 14;
}
}

message Status {}

// APIVersion is the API version of the object.
string apiVersion = 1;
// Kind is the resource name (i.e. `User`).
string kind = 2;
// Metadata is the object's metadata.
octelium.api.main.meta.v1.Metadata metadata = 3;
// Spec is the User specification.
Spec spec = 4;
// Status is the current status of the User.
Status status = 5;
}


message CloudProviderList {
// APIVersion is the API version of the object.
string apiVersion = 1;
// Kind is the resource name (i.e. `CloudProviderList`).
string kind = 2;
// Items is the list of Users.
repeated CloudProvider items = 3;
// ListResponseMeta is common information about the list.
octelium.api.main.meta.v1.ListResponseMeta listResponseMeta = 4;
}

octelium.api.main.enterprise.v1.Collecto.title:
message Loki {
message Auth {
message Bearer {
oneof type { string fromSecret = 1; }
}
message Custom {
message Value {
oneof type { string fromSecret = 1; }
}

string header = 1;
Value value = 2;
}

oneof type {
Bearer bearer = 1;
Custom custom = 2;
}
}
string endpoint = 1;
map<string, string> headers = 2;
Auth auth = 3;
}
